def generate_blokus_pieces(n):
    """
    Generates all possible Blokus pieces of size n, considering rotations and reflections.

    Args:
        n: The number of squares in the piece.

    Returns:
        A set of frozensets, where each frozenset represents a unique Blokus piece.
        Each inner frozenset contains tuples representing the coordinates of the squares in the piece.
    """

    if n <= 0:
        return set()

    if n == 1:
        return {frozenset({(0, 0)})}

    pieces = set()

    def normalize(piece):
        """Normalizes a piece by translating it to the origin."""
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """Rotates a piece 90 degrees clockwise."""
        return frozenset((y, -x) for x, y in piece)

    def reflect(piece):
        """Reflects a piece across the y-axis."""
        return frozenset((-x, y) for x, y in piece)

    def add_piece(piece):
        """Adds a piece to the set of pieces, considering rotations and reflections."""
        normalized_piece = normalize(piece)
        for _ in range(4):
            if normalized_piece not in pieces:
                pieces.add(normalized_piece)
            normalized_piece = rotate(normalized_piece)

        normalized_piece = reflect(normalize(piece))
        for _ in range(4):
            if normalized_piece not in pieces:
                pieces.add(normalized_piece)
            normalized_piece = rotate(normalized_piece)

    def find_pieces(current_piece):
        """Recursively finds all possible pieces."""
        if len(current_piece) == n:
            add_piece(current_piece)
            return

        for x, y in list(current_piece):
            neighbors = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
            for nx, ny in neighbors:
                if (nx, ny) not in current_piece:
                    find_pieces(current_piece | {(nx, ny)})

    find_pieces({(0, 0)})
    return pieces

