        return set()
    if n == 1:
        return {frozenset({(0, 0)})}

    pieces = set()

    def normalize(piece):
        """Normalizes a piece to its top-left-most representation."""
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """Rotates a piece 90 degrees clockwise."""
        return frozenset((y, -x) for x, y in piece)

    def flip(piece):
        """Flips a piece horizontally."""
        return frozenset((-x, y) for x, y in piece)

    def add_square(piece):
        """Adds a square to a piece in all possible ways."""
        new_pieces = set()
        for x, y in piece:
            neighbors = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
            for nx, ny in neighbors:
                new_piece = piece | {(nx, ny)}
                if len(new_piece) == n:
                    new_pieces.add(new_piece)
        return new_pieces

