    def normalize(piece):
        """Normalizes a piece to its top-left-most representation."""
        min_x = min(x for x, y in piece)
        min_y = min(y for x, y in piece)
        return frozenset((x - min_x, y - min_y) for x, y in piece)

    def rotate(piece):
        """Rotates a piece 90 degrees clockwise."""
        return frozenset((y, -x) for x, y in piece)

    def reflect(piece):
        """Reflects a piece across the y-axis."""
        return frozenset((-x, y) for x, y in piece)

    def add_piece(piece):
        """Adds a piece to the set of pieces, removing duplicates."""
        normalized_piece = normalize(piece)

        variants = {normalized_piece}
        for _ in range(3):
            normalized_piece = rotate(normalized_piece)
            variants.add(normalized_piece)

        reflected_piece = reflect(normalize(piece))
        variants.add(reflected_piece)
        for _ in range(3):
            reflected_piece = rotate(reflected_piece)
            variants.add(reflected_piece)

        for variant in variants:
            if variant in pieces:
                return

        pieces.add(normalize(piece))

    def generate_recursive(current_piece, remaining_squares):
